@app.route('/reset', methods=['POST'])
@limiter.limit("10 per hour")
def reset_password():
    data = request.get_json()
    token = data.get('token')
    new_password = data.get('password')
    
    if not token or not new_password:
        return jsonify({'error': 'Token and password required'}), 400
    
    # Verify token
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT email FROM password_resets WHERE token = ? AND created_at > ?", 
              (token, time.time() - 3600))
    result = c.fetchone()
    
    if not result:
        return jsonify({'error': 'Invalid or expired token'}), 400
    
    email = result[0]
    
    # Update password (mock)
    # In reality, hash the password before storing
    c.execute("UPDATE users SET password = ? WHERE email = ?", (new_password, email))
    conn.commit()
    
    # Remove used token
    c.execute("DELETE FROM password_resets WHERE token = ?", (token,))
    conn.commit()
    conn.close()
    
    return jsonify({'message': 'Password reset successfully'}), 200

